INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 21, 0, 0, "vo_asb_0726", "", "vo_asb", "", "", 72032, 72);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, 11, 10, 1, "そりゃそうですよね……\nいきなり前のめり過ぎ太郎でした……", 0, 1, 1, 0, 72033, 72);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 91, 0, 0, "", "", 0, "", "", 72034, 72);
