INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 21, 0, 0, "vo_asb_0824", "", "vo_asb", "", "", 82024, 82);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, 11, 10, 1, "と、不退転の決意を申し上げたら、\nミサト様、「は～い♪」と、\n二つ返事で分かってくださって。", 0, 1, 1, 0, 82025, 82);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 91, 0, 0, "", "", 0, "", "", 82026, 82);
